import React from 'react';
import { useInView } from '../hooks/useInView';

const reviews = [
  { name:'Kritika Parihar', location:'Dilsukhnagar, Hyderabad', rating:5, review:'They did a fantastic job painting our home! They were punctual, professional, and very detail-oriented. The prep work was thorough, and they left the place spotless every day. Highly recommend!', initial:'R', color:'#2563eb' },
  { name:'Nagaraja C', location:'LB Nagar, Hyderabad', rating:5, review:'Good experience with baharul islam and his team at Whitefield painting services, They were very professional, used high -quality materials, and completed the job on time. Baharul is very polite and ensures the costomer is happy with every detail, Highly recommended for any painting needs!"', initial:'P', color:'#0369a1' },
  { name:'Apoorva Malgatti', location:'Kothapet, Hyderabad', rating:5, review:'Baharul and his team did an excellent job. Very professional, punctual, and neat with the work. The finishing was clean and exactly as expected.', initial:'M', color:'#475569' },
  { name:'Sunita Reddy', location:'Nagole, Hyderabad', rating:5, review:'Beautiful service.They are very professional and do the painting work really great. ', initial:'S', color:'#1d4ed8' },
];

export default function Reviews() {
  const [ref, inView] = useInView();

  return (
    <section id="reviews" className="py-28" style={{ background:'#f1f5f9' }} ref={ref}>
      <div className="max-w-7xl mx-auto px-6">
        <div className={`mb-16 text-center reveal ${inView?'visible':''}`}>
          <span className="section-tag">Testimonials</span>
          <h2 className="section-title text-ink">What Our <span className="gradient-text">Customers Say</span></h2>
          <p className="font-body text-muted mt-4 max-w-xl mx-auto">Real reviews from homeowners across Hyderabad who trusted us with their homes.</p>
        </div>

        <div className="grid md:grid-cols-2 gap-6">
          {reviews.map((r,i) => (
            <div key={i}
              className={`reveal delay-${Math.min(i,6)} ${inView?'visible':''} card-lift bg-white rounded-2xl p-8 group cursor-default border-l-4 shadow-sm`}
              style={{ borderLeftColor:r.color }}>
              <div className="flex gap-1 mb-5">
                {[...Array(r.rating)].map((_,j) => (
                  <span key={j} className="text-lg transition-all duration-200" style={{ color:'#f59e0b', transitionDelay:`${j*50}ms` }}>★</span>
                ))}
              </div>
              <p className="font-body leading-relaxed mb-6 italic" style={{ color:'#334155', fontSize:'1.02rem' }}>"{r.review}"</p>
              <div className="flex items-center gap-4 pt-5 border-t border-slate-100">
                <div className="w-12 h-12 rounded-full flex items-center justify-center shadow group-hover:scale-110 transition-transform duration-300"
                  style={{ background:`linear-gradient(135deg,${r.color},${r.color}99)` }}>
                  <span className="font-display font-bold text-white text-lg">{r.initial}</span>
                </div>
                <div>
                  <div className="font-display font-semibold text-ink">{r.name}</div>
                  <div className="font-mono text-xs text-muted tracking-wide">{r.location}</div>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Brand marquee */}
        <div className={`mt-16 overflow-hidden pt-10 border-t border-slate-200 reveal ${inView?'visible':''}`}>
          <p className="text-center font-mono text-xs tracking-widest uppercase mb-6 text-muted">Trusted Paint Brands We Use</p>
          <div className="marquee-track select-none">
            {[...Array(2)].map((_,k) => (
              <div key={k} className="flex gap-16 mr-16 items-center">
                {['🎨 Asian Paints','✨ Berger Paints','🏆 Dulux','⭐ Nerolac','💎 JSW Paints','🌟 Kansai'].map((brand,j) => (
                  <span key={j} className="font-display text-xl font-semibold whitespace-nowrap cursor-default text-slate-400 hover:text-blue-600 transition-colors">{brand}</span>
                ))}
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}
